public class MaxSubarrayDC {

    static int maxCrossing(int[] arr, int l, int mid, int r) {
        int leftSum = Integer.MIN_VALUE, sum = 0;
        for (int i = mid; i >= l; i--) {
            sum += arr[i];
            leftSum = Math.max(leftSum, sum);
        }
        int rightSum = Integer.MIN_VALUE; sum = 0;
        for (int i = mid + 1; i <= r; i++) {
